sys_script_include.script:
var ConfigurationItemFetcher = Class.create();

ConfigurationItemFetcher.prototype = Object.extendsObject(
    global.AbstractAjaxProcessor, 
	{
        getConfigItemsCount: function() {
            const configItemId = this.getParameter('sysparm_config_item_id');
            let count = 0;

            if (configItemId) {
                // 1. Get the class of the current CI
                const configItemGR = new GlideRecord('cmdb_ci');

                if (configItemGR.get(configItemId)) {
                    var className = configItemGR.getValue('sys_class_name');

                    // 2. Perform aggregate count on the same class
                    var ga = new GlideAggregate('cmdb_ci');
                    ga.addQuery('sys_class_name', className);
                    ga.addAggregate('COUNT');
                    ga.query();

                    if (ga.next()) {
                        count = ga.getAggregate('COUNT');
                    }
                }
            }

            return count;
        },
        type: 'ConfigurationItemFetcher'
    }
);
